#include<bits/stdc++.h>
using namespace std;
int main(void){
	int n,m,x1,x2,y1,y2,t[1145][1145];
	cin>>n>>m;
	for(int k=1;k<=m;++k){
		cin>>x1>>y1>>x2>>y2;
		for(int i=x1;i<=x2;++i)
			for(int j=y1;j<=y2;++j)++t[i][j];
	}
	for(int i=1;i<=n;++i){
		for(int j=1;j<=n;++j)
			cout<<t[i][j]<<' ';
		cout<<'\n';
	}
	return false;
}
